// Loop over input items and add a new field called 'myNewField' to the JSON of each one

const all_projects = $('Option aggregate').first().json.values;
const nameToFind = $input.first().json['Select a project']; // Replace with the name you want to find
const found = all_projects.find(item => item.name === nameToFind);
return [{ json: { id: found ? found.id : null } }];


// for (const item of $input.all()) {
//   item.json.myNewField = 1;
// }

// return $input.all();

const submittedName = $('Commit Form').first().json['Workflow Name'].trim();
const commitMsg = $('Commit Form').first().json['Commit Message'];
const action = $('Commit Form').first().json['GitHub File Action'];
const all = $input.all();
const found = all.find(i => i.json.name.toLowerCase() === submittedName.toLowerCase());
if (!found) throw new Error(`Workflow "${submittedName}" not found. Check the name and try again.`);
return [{ json: { workflow_id: found.json.id, workflow_name: found.json.name, github_file_name: found.json.name + '-' + found.json.id + '.json', commit_message: commitMsg, action_hint: action } }];

const githubFiles = $input.all().map(i => i.json.name);
const vals = $('Carry Values').first().json;
const fileExists = githubFiles.includes(vals.github_file_name);
let action;
if (vals.action_hint === 'Force create new file') action = 'create';
else if (vals.action_hint === 'Force update existing file') action = 'update';
else action = fileExists ? 'update' : 'create';
return [{ json: { ...vals, action, file_exists: fileExists } }];

