const allItems = $input.all();

// Workflows have 'active' field; GitHub repos have 'full_name'
const workflowMap = allItems
  .filter(i => i.json.active !== undefined && !i.json.isArchived)
  .map(i => ({ name: i.json.name, id: i.json.id }));

const repoOptions = allItems
  .filter(i => i.json.full_name !== undefined)
  .map(i => ({ option: i.json.full_name }));

repoOptions.unshift({ option: '-- Create New Repository --' });

return [{ json: {
  workflow_options: workflowMap.map(w => ({ option: w.name })),
  repo_options: repoOptions,
  workflow_map: workflowMap
}}];

const wfName = $json['Select Workflow'];
const repoChoice = $json['Select or Create Repository'];
const newRepo = $json['New Repository Name'];
const commitMsg = $json['Commit Message'];

const wfMap = $('Build Form Options').first().json.workflow_map;
const wf = wfMap.find(w => w.name === wfName);

const isNew = repoChoice === '-- Create New Repository --';
const targetRepo = isNew ? newRepo : repoChoice;
const [owner, repoName] = targetRepo.includes('/') ? targetRepo.split('/') : ['', targetRepo];

return [{ json: {
  workflow_name: wfName,
  workflow_id: wf ? wf.id : null,
  repo_owner: owner,
  repo_name: repoName,
  is_new_repo: isNew,
  commit_message: commitMsg,
  file_name: `${wfName.replace(/[^a-zA-Z0-9_-]/g,'_')}-${wf ? wf.id : 'unknown'}.json`
}}];

const all_projects = $('Workflow-Aggregate').first().json.values;
const nameToFind = $('Form').first().json['Select a Workflow'];
const found = all_projects.find(item => item.name === nameToFind);
return [{ json: { id: found ? found.id : null } }];

